#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. All operations,
   including the function call, are timed. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B) {
    /* Work with raw pointers for maximum speed and to avoid any
       additional bounds checks that std::vector may perform. */
    double *restrict a = A.data();
    double *restrict b = B.data();

    /* Precompute the coefficient once. */
    const double coeff = 0.33333;

    /* The kernel is inherently parallel across spatial points.
       Two nested loops per time step are fully independent, so we
       parallelise each loop separately. */
    for (int t = 0; t < tsteps; ++t) {
        /* Compute B from A */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            b[i] = coeff * (a[i-1] + a[i] + a[i+1]);
        }

        /* Compute A from B */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            a[i] = coeff * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
