void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    // Form  B := alpha*A**T*B.
    // A is MxM
    // B is MxN

    // Parallelise the outer two loops – each (i,j) update is independent.
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            double sum = 0.0;
            // Accumulate contributions from rows k > i (i.e. A[k][i]).
            for (int k = i + 1; k < m; ++k) {
                sum += A[k][i] * B[k][j];
            }
            B[i][j] = alpha * (B[i][j] + sum);
        }
    }
}
