void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b)
{
    // Grab raw pointers for faster access
    double*          x_ptr = x.data();
    const double*    b_ptr = b.data();

    for (int i = 0; i < n; ++i) {
        // Use a temporary to avoid unneeded memory accesses
        double sum = b_ptr[i];

        // Prefer pointer arithmetic over bounds‑checking vector access
        const std::vector<double>& Li = L[i];
        const double*               Li_ptr = Li.data();

        for (int j = 0; j < i; ++j) {
            sum -= Li_ptr[j] * x_ptr[j];
