   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {

    /* 1. Zero y (parallelised) */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j) {
        y[j] = 0.0;
    }

    /* 2. Main loop: compute tmp = A * x, then y += Aᵀ * tmp */
    #pragma omp parallel for schedule(static) collapse(1)
    for (int i = 0; i < m; ++i) {
        double row_sum = 0.0;

        /* compute tmp[i] = A[i] * x */
        const std::vector<double>& Ai = A[i];
        for (int j = 0; j < n; ++j) {
            row_sum += Ai[j] * x[j];
        }
        tmp[i] = row_sum;

        /* accumulate into y */
        for (int j = 0; j < n; ++j) {
            #pragma omp atomic update
            y[j] += Ai[j] * row_sum;
        }
    }
