    for (int i = 0; i < n; ++i) {
        // Scale lower triangular part of C by beta once
        for (int j = 0; j <= i; ++j)
            C[i][j] *= beta;

        // Accumulate outer‑product contributions
        for (int k = 0; k < m; ++k) {
            double aik = A[i][k];
            double bkj = B[i][k];
            for (int j = 0; j <= i; ++j) {
                double t1 = A[j][k] * aik * alpha;
                double t2 = B[j][k] * bkj * alpha;
                C[i][j] += t1 + t2;
            }
        }
    }
