void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C) {

    /* Parallelise over rows of C (i‑loop).  This keeps the data
     * in registers across the inner k/j loops and gives a good
     * balance for the 8‑thread OpenMP runtime. */
