        /* Raw pointers to the current row for random access
         * without a double vector lookup every time. */
        double* c_row = C[i].data();
        const double* a_row = A[i].data();

        /* Scale C[i][j] by beta once, before accumulating. */
        for (int j = 0; j < nj; ++j) {
            c_row[j] *= beta;
        }

        /* Accumulate the product A * B into C[i][*].  The
         * outer k‑loop is kept to preserve the original
         * algorithm and cache locality of B. */
        for (int k = 0; k < nk; ++k) {
            double aik = alpha * a_row[k];
            const double* b_row = B[k].data();
            for (int j = 0; j < nj; ++j) {
                c_row[j] += aik * b_row[j];
            }
        }
    }
