/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha,
                double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D)
{
    /* --- first GEMM: tmp = alpha * A * B ------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < ni; ++i) {
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            double* restrict a_row = A[i].data();
            double* restrict b_col = B.data()[0] + j;  // B[k][j]
            for (int k = 0; k < nk; ++k) {
                sum += a_row[k] * b_col[k * nj];
            }
            tmp[i][j] = alpha * sum;
        }
    }

    /* --- second GEMM: D = beta*D + tmp * C ----------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < ni; ++i) {
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            double* restrict tmp_row = tmp[i].data();
            double* restrict c_col = C.data()[0] + j;   // C[k][j]
            for (int k = 0; k < nj; ++k) {
                sum += tmp_row[k] * c_col[k * nl];
            }
            D[i][j] = beta * D[i][j] + sum;
        }
    }
}
