void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    /* ------------------------------------------------------------------
     * 1)  Compute column means
     * ------------------------------------------------------------------ */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean[j] = sum / n;
    }

    /* ------------------------------------------------------------------
     * 2)  Center the data (subtract the mean)
     * ------------------------------------------------------------------ */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        std::vector<double> &row = data[i];
        for (int j = 0; j < m; ++j) {
            row[j] -= mean[j];
        }
    }

    /* ------------------------------------------------------------------
     * 3)  Compute covariance matrix
     *    We only compute the upper triangle and mirror it.
     * ------------------------------------------------------------------ */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double s = 0.0;
            for (int k = 0; k < n; ++k) {
                s += data[k][i] * data[k][j];
            }
            double v = s / (n - 1.0);
            cov[i][j] = v;
            cov[j][i] = v;   // mirror for symmetry
        }
    }
}
