/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {

    //  Form  C := alpha*A*B + beta*C
    //  A is MxM, B is MxN, C is MxN
    //  The algorithm is identical to the original but uses
    //  cache‑friendly accesses and OpenMP parallelization.

    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j) {
        for (int i = 0; i < m; ++i) {
            double Bj = B[i][j];          // cache B[i][j]
            double temp2 = 0.0;
            double* Crow   = C[i].data();
            double* Cprev  = nullptr;          // will set inside k loop
            double* Arow   = A[i].data();

            for (int k = 0; k < i; ++k) {
                // update C[k][j] and accumulate temp2
                Cprev = C[k].data();
                double Aik = Arow[k];
                Cprev[j] += alpha * Bj * Aik;
                temp2 += B[k][j] * Aik;
            }

            // final update of C[i][j]
            Crow[j] = beta * Crow[j] + alpha * Bj * Arow[i] + alpha * temp2;
        }
    }
}
