void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Pre‑allocate a temporary array for the intermediate row to reduce
    // repeated dereferencing of std::vector::operator[] inside the inner loop.
    std::vector<int> temp_row;
    temp_row.resize(n);

    // The outer loop over k must be sequential to preserve the algorithmic order.
    for (int k = 0; k < n; ++k) {
        // Copy the k‑th row once; this avoids accessing path[k] in the innermost loops.
        const std::vector<int>& row_k = path[k];

        // Parallelize the i‑loop (outermost of the inner two loops).
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < n; ++i) {
            // Grab a pointer to the current row for fast access.
            std::vector<int>& row_i = path[i];
            const int* row_k_data = row_k.data();
            int* row_i_data = row_i.data();

            // Use a local copy of row_i to avoid repeated write conflicts.
            std::copy(row_i.begin(), row_i.end(), temp_row.begin());

            for (int j = 0; j < n; ++j) {
                // Compute path[i][j] = min(path[i][j], path[i][k] + path[k][j])
                int new_val = temp_row[j] + row_k_data[j];
                if (new_val < row_i_data[j]) {
                    row_i_data[j] = new_val;
                }
            }
        }
    }
}
