/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    // Store raw pointers to each row of the matrices for faster access
    std::vector<double*> Aptr(n), Bptr(n);
    for (int i = 0; i < n; ++i) {
        Aptr[i] = A[i].data();
        Bptr[i] = B[i].data();
    }
    const double* X = x.data();
    double* T = tmp.data();
    double* Y = y.data();

    // Parallelize the outer loop
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sumA = 0.0;
        double sumB = 0.0;
        double* aRow = Aptr[i];
        double* bRow = Bptr[i];
        // Unroll 4x for inner loop
        int j = 0;
        for (; j + 3 < n; j += 4) {
            double x0 = X[j],     x1 = X[j+1],     x2 = X[j+2],     x3 = X[j+3];
            sumA += aRow[j]   * x0 + aRow[j+1] * x1 + aRow[j+2] * x2 + aRow[j+3] * x3;
            sumB += bRow[j]   * x0 + bRow[j+1] * x1 + bRow[j+2] * x2 + bRow[j+3] * x3;
        }
        for (; j < n; ++j) {
            sumA += aRow[j] * X[j];
            sumB += bRow[j] * X[j];
        }
        T[i] = sumA;
        Y[i] = alpha * sumA + beta * sumB;
    }
}
