void kernel_jacobi_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A,
		      std::vector<std::vector<double>>& B) {
    /* Flatten 2‑D vectors to 1‑D arrays for cache‑friendly access. */
    const size_t N = static_cast<size_t>(n);
    const size_t NN = N * N;
    std::vector<double> &a = reinterpret_cast<std::vector<double>&>(A);
