        for (int i = 1; i < n - 1; ++i) {
            const size_t base = static_cast<size_t>(i) * N;
            const size_t im1 = static_cast<size_t>(i - 1) * N;
            const size_t ip1 = static_cast<size_t>(i + 1) * N;
            for (int j = 1; j < n - 1; ++j) {
                const size_t idx = base + j;
                b[idx] = 0.2 * ( a[idx]
                               + a[base + j - 1]
                               + a[base + j + 1]
                               + a[ip1 + j]
                               + a[im1 + j] );
