#include <cmath>
#include <vector>
#include <omp.h>

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev)
{
    const double eps = 0.1;
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* ---------------------------------------------
       1) compute column means
       --------------------------------------------- */
    #pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean[j] = sum / n;
    }

    /* ---------------------------------------------
       2) compute column stddevs
       --------------------------------------------- */
    #pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double var = 0.0;
        const double col_mean = mean[j];
        for (int i = 0; i < n; ++i) {
            double d = data[i][j] - col_mean;
            var += d * d;
        }
        var /= n;
        double sd = std::sqrt(var);
        stddev[j] = (sd <= eps) ? 1.0 : sd;
    }

    /* ---------------------------------------------
       3) normalize data in place
       --------------------------------------------- */
    #pragma omp parallel for
    for (int i = 0; i < n; ++i) {
        double* row = data[i].data();
        for (int j = 0; j < m; ++j) {
            row[j] = (row[j] - mean[j]) * inv_sqrt_n / stddev[j];
        }
    }

    /* ---------------------------------------------
       4) compute correlation matrix
       --------------------------------------------- */
    // set diagonal to 1
    #pragma omp parallel for
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;
    }

    // off‑diagonal entries (symmetrically)
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < m - 1; ++i) {
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            corr[i][j] = sum;
            corr[j][i] = sum;
        }
    }
}
