/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n, std::vector<std::vector<double>>& A)
{
    // Parallelise the outer loop over rows i.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
    {
        std::vector<double>& row_i = A[i];

        /* Compute the strictly lower part of the i‑th row. */
        for (int j = 0; j < i; ++j)
        {
            std::vector<double>& row_j = A[j];
            double sum = 0.0;

            /* Unroll the innermost dot product a bit. */
            const int k_limit = j;
            int k = 0;
            for (; k <= k_limit - 3; k += 3)
            {
                sum += row_i[k]   * row_j[k];
                sum += row_i[k+1] * row_j[k+1];
                sum += row_i[k+2] * row_j[k+2];
            }
            for (; k < k_limit; ++k)
            {
                sum += row_i[k] * row_j[k];
            }

            row_i[j] = (row_i[j] - sum) / row_j[j];
        }

        /* Diagonal entry: subtract the squared norm of the i‑th row
           up to the preceding column. */
        double diag = row_i[i];
        for (int k = 0; k < i; ++k)
        {
            const double v = row_i[k];
            diag -= v * v;
        }
        row_i[i] = std::sqrt(diag);
    }
}
