   including the call and return. */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y)
{
    // Alias pointers to the row data for a few nanoseconds of speed‑ups.
    // The std::vector guarantees row alignment and contiguity.
    std::vector<double*> row(n);
    for (int i = 0; i < n; ++i)
        row[i] = A[i].data();

    // ---------- LU decomposition ----------
    for (int i = 0; i < n; ++i) {
        // L‑matrix below the diagonal
        for (int j = 0; j < i; ++j) {
            double w = row[i][j];
            // Zig‑zag inner product
            for (int k = 0; k < j; ++k)
                w -= row[i][k] * row[k][j];
            row[i][j] = w / row[j][j];
        }
        // U‑matrix on and above the diagonal
        for (int j = i; j < n; ++j) {
            double w = row[i][j];
            for (int k = 0; k < i; ++k)
                w -= row[i][k] * row[k][j];
            row[i][j] = w;
        }
    }

    // ---------- Forward substitution  (L y = b) ----------
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        for (int j = 0; j < i; ++j)
            w -= row[i][j] * y[j];
        y[i] = w;             // L[i][i] == 1.0
    }

    // ---------- Backward substitution (U x = y) ----------
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
        for (int j = i + 1; j < n; ++j)
            w -= row[i][j] * x[j];
        x[i] = w / row[i][i];
    }
}
