void kernel_seidel_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A) {

    const double inv9 = 1.0 / 9.0;          // pre‑compute the reciprocal
    const int maxI = n - 2;                 // last row index that can be updated
    const int maxJ = n - 2;                 // last column index that can be updated

