    // parallel over the spatial indices.
    for (int t = 0; t < tsteps; ++t) {
        // Parallelise the two inner loops with a collapsed iteration space.
        // Static schedule gives a good balance on a modern machine with few cores.
#pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i <= maxI; ++i) {
            // Pointers to the three rows used in the stencil
            double* prev = A[i-1].data();
            double* cur  = A[i  ].data();
            double* next = A[i+1].data();

            for (int j = 1; j <= maxJ; ++j) {
                cur[j] = (prev[j-1] + prev[j] + prev[j+1] +
                          cur [j-1] + cur [j] + cur [j+1] +
                          next[j-1] + next[j] + next[j+1]) * inv9;
            }
        }
