/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {
    for (int k = 0; k < n; ++k) {
        /* 1. compute norm of column k of A */
        double nrm = 0.0;
        #pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i) {
            double val = A[i][k];
            nrm += val * val;
        }
        R[k][k] = std::sqrt(nrm);

        /* 2. normalize column k to form Q[:,k] */
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            Q[i][k] = A[i][k] / R[k][k];
        }

        /* 3. orthogonalize remaining columns */
        #pragma omp parallel for schedule(static)
        for (int j = k + 1; j < n; ++j) {
            /* dot product Q[:,k] · A[:,j] */
            double rkj = 0.0;
            #pragma omp parallel for reduction(+:rkj) schedule(static)
            for (int i = 0; i < m; ++i) {
                rkj += Q[i][k] * A[i][j];
            }
            R[k][j] = rkj;

            /* subtract projection */
            #pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                A[i][j] -= Q[i][k] * rkj;
            }
        }
    }
}
