/* Kernel implementation – optimized for speed while preserving exact behaviour. */
void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table)
{
    /* Flatten the 2‑D table into a 1‑D vector for cache locality. */
    std::vector<int> flat(n * n, 0);

    auto idx = [n](int i, int j) { return i * n + j; };
    auto maxv = [](int a, int b) { return (a > b) ? a : b; };

    /* Lambda for base‑pair matching: 1 if (b1+b2)==3 else 0. */
    auto match = [](int b1, int b2) -> int {
        return (b1 + b2 == 3) ? 1 : 0;
    };

    /* Main dynamic‑programming loop (diagonal sweep). */
    for (int i = n - 1; i >= 0; --i) {
        for (int j = i + 1; j < n; ++j) {
            int best = 0;

            /* Exclude j: take value from left cell */
            if (j - 1 >= 0)
                best = maxv(best, flat[idx(i, j - 1)]);

            /* Exclude i: take value from upper cell */
            if (i + 1 < n)
                best = maxv(best, flat[idx(i + 1, j)]);

            /* Pair i & j (or skip pairing when i >= j-1) */
            if (j - 1 >= 0 && i + 1 < n) {
                int pair_val = flat[idx(i + 1, j - 1)];
                if (i < j - 1) {
                    pair_val += match(seq[i], seq[j]);
                }
                best = maxv(best, pair_val);
            }

            /* Split between k and k+1 */
            for (int k = i + 1; k < j; ++k) {
                int val = flat[idx(i, k)] + flat[idx(k + 1, j)];
                if (val > best) best = val;
            }

            flat[idx(i, j)] = best;
        }
    }

    /* Copy results back into the 2‑D table. */
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            table[i][j] = flat[idx(i, j)];
        }
    }
}
