    auto pack = [&](const std::vector<std::vector<std::vector<double>>>& src,
                    std::vector<double>& dst)
    {
        for (int i = 0; i < n; ++i)
            for (int j = 0; j < n; ++j)
                for (int k = 0; k < n; ++k)
                    dst[i*stride*stride + j*stride + k] = src[i][j][k];
    };

    auto unpack = [&](const std::vector<double>& src,
                      std::vector<std::vector<std::vector<double>>>& dst)
    {
        for (int i = 0; i < n; ++i)
            for (int j = 0; j < n; ++j)
                for (int k = 0; k < n; ++k)
                    dst[i][j][k] = src[i*stride*stride + j*stride + k];
    };

    pack(A, a);
    pack(B, b);

    const int inner = (n-2)*(n-2)*(n-2);
    const int start = 1, end = n-1;               // loop bounds

    for (int t = 1; t <= tsteps; ++t) {
        /* ---- First update: A → B ---- */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = start; i < end; ++i) {
            for (int j = start; j < end; ++j) {
                int base = i*stride*stride + j*stride;
                for (int k = start; k < end; ++k) {
                    int idx = base + k;
                    int idxM = idx - stride*stride;     // (i-1,j,k)
                    int idxP = idx + stride*stride;     // (i+1,j,k)
                    int idxJm = idx - stride;           // (i,j-1,k)
                    int idxJp = idx + stride;           // (i,j+1,k)
                    int idxKm = idx - 1;                // (i,j,k-1)
                    int idxKp = idx + 1;                // (i,j,k+1)

