            }
        }

        /* ---- Second update: B → A ---- */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = start; i < end; ++i) {
            for (int j = start; j < end; ++j) {
                int base = i*stride*stride + j*stride;
                for (int k = start; k < end; ++k) {
                    int idx = base + k;
                    int idxM = idx - stride*stride;
                    int idxP = idx + stride*stride;
                    int idxJm = idx - stride;
                    int idxJp = idx + stride;
                    int idxKm = idx - 1;
                    int idxKp = idx + 1;

