        // Forward 1st pass
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        for (int j = 0; j < h; ++j) {
            y1_row[j] = a1 * in_row[j] + a2 * xm1 + b1 * ym1 + b2 * ym2;
            xm1 = in_row[j];
            ym2 = ym1;
            ym1 = y1_row[j];
        }
        // Backward 1st pass
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        for (int j = h - 1; j >= 0; --j) {
            y2_row[j] = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            xp2 = xp1;
            xp1 = in_row[j];
            yp2 = yp1;
            yp1 = y2_row[j];
        }
        // Sum
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = c1 * (y1_row[j] + y2_row[j]);
    }

#pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        // Forward 2nd pass
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            y1[i][j] = a5 * imgOut[i][j] + a6 * tm1 + b1 * ym1 + b2 * ym2;
            tm1 = imgOut[i][j];
            ym2 = ym1;
            ym1 = y1[i][j];
        }
        // Backward 2nd pass
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w - 1; i >= 0; --i) {
            y2[i][j] = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            tp2 = tp1;
            tp1 = imgOut[i][j];
            yp2 = yp1;
            yp1 = y2[i][j];
        }
        // Final sum
        for (int i = 0; i < w; ++i)
            imgOut[i][j] = c2 * (y1[i][j] + y2[i][j]);
