#include <vector>
#include <cmath>
#include <cstring>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* Based on a Fortran code fragment from Figure 5 of
 * "Automatic Data and Computation Decomposition on Distributed Memory Parallel Computers"
 * by Peizong Lee and Zvi Meir Kedem, TOPLAS, 2002
 */

void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q)
{
    /* Pre‑compute constants once. */
    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1  = 2.0, B2 = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a    = -mul1 / 2.0;
    const double b    = 1.0 + mul1;
    const double c    = a;
    const double d    = -mul2 / 2.0;
    const double e    = 1.0 + mul2;
    const double f    = d;

    const int ndim = n;
    const int innerSize = ndim - 2;               // number of interior rows/cols
    double* restrict pu = &u[0][0];
    double* restrict pv = &v[0][0];
    double* restrict pp = &p[0][0];
    double* restrict pq = &q[0][0];

    /* buffer for diagonals – reused across time steps */
    double* restrict pbuf = new double[innerSize * ndim];
    double* restrict qbuf = new double[innerSize * ndim];

    for (int t = 1; t <= tsteps; ++t)
    {
        /* First sweep: update v using u */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < ndim - 1; ++i)
        {
            /* first row */
            pv[0*ndim + i] = 1.0;
            pp[i*ndim + 0] = 0.0;
            pq[i*ndim + 0] = pv[0*ndim + i];

            /* forward sweep on j */
            for (int j = 1; j < ndim - 1; ++j)
            {
                const double denom = a * pp[i*ndim + (j-1)] + b;
                pp[i*ndim + j] = -c / denom;

                const double num = (-d * pu[(j-1)*ndim + (i-1)]
                                   + (1.0 + 2.0 * d) * pu[(j-1)*ndim + i]
                                   - f * pu[(j-1)*ndim + (i+1)]
                                   - a * pq[i*ndim + (j-1)]);
                pq[i*ndim + j] = num / denom;
            }

            /* last row */
            pv[(ndim-1)*ndim + i] = 1.0;

            /* backward sweep on j */
            for (int j = ndim-2; j >= 1; --j)
            {
                pv[j*ndim + i] = pp[i*ndim + j] * pv[(j+1)*ndim + i] + pq[i*ndim + j];
            }
        }

        /* Second sweep: update u using v */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < ndim - 1; ++i)
        {
            /* first column */
            pu[i*ndim + 0] = 1.0;
            pp[i*ndim + 0] = 0.0;
            pq[i*ndim + 0] = pu[i*ndim + 0];

            /* forward sweep on j */
            for (int j = 1; j < ndim - 1; ++j)
            {
                const double denom = d * pp[i*ndim + (j-1)] + e;
                pp[i*ndim + j] = -f / denom;

                const double num = (-a * pv[(i-1)*ndim + j]
                                   + (1.0 + 2.0 * a) * pv[i*ndim + j]
                                   - c * pv[(i+1)*ndim + j]
                                   - d * pq[i*ndim + (j-1)]);
                pq[i*ndim + j] = num / denom;
            }

            /* last column */
            pu[i*ndim + (ndim-1)] = 1.0;

            /* backward sweep on j */
            for (int j = ndim-2; j >= 1; --j)
            {
                pu[i*ndim + j] = pp[i*ndim + j] * pu[i*ndim + (j+1)] + pq[i*ndim + j];
            }
        }
    }

    delete[] pbuf;
    delete[] qbuf;
}
